// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import org.junit.jupiter.api.Test;

class ThompsonSamplingBanditPolicyPersistenceTest {

	@Test
	void persistsPlannerStatsAcrossPolicyInstances() throws IOException {
		Path storeFile = Files.createTempFile("joinengine-bandit", ".json");
		try {
			BanditStore store = new FileBanditStore(storeFile);
			ThompsonSamplingBanditPolicy first = new ThompsonSamplingBanditPolicy(store, 7L);
			for (int i = 0; i < 200; i++) {
				first.reportOutcome("region-a", "planner-fast", 15.0d);
				first.reportOutcome("region-a", "planner-slow", -15.0d);
			}

			ThompsonSamplingBanditPolicy second = new ThompsonSamplingBanditPolicy(store, 7L);
			List<String> selected = second.selectPlanners("region-a",
					List.of("planner-fast", "planner-slow"), 1);

			assertThat(selected).containsExactly("planner-fast");
		} finally {
			Files.deleteIfExists(storeFile);
		}
	}
}
